fn od_ic() -> vec2f { return vec2f(-9.0, 32.0); }

fn od_suncol(el: f32) -> vec3f {
  return mix(vec3f(1.30, 0.45, 0.16), vec3f(1.15, 1.05, 0.90), smoothstep(0.02, 0.55, el));
}

fn od_sky(rd: vec3f, sd: vec3f, md: vec3f, t: f32) -> vec3f {
  let el = uni(1);
  let y = max(rd.y, 0.0);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);

  // dome: night indigo → day blue, horizon warms at low sun
  let zen = mix(vec3f(0.012, 0.018, 0.045), vec3f(0.16, 0.36, 0.65), day);
  let horDay = mix(vec3f(1.00, 0.42, 0.16), vec3f(0.46, 0.58, 0.72), smoothstep(0.10, 0.55, el));
  let hor = mix(vec3f(0.035, 0.035, 0.075), horDay, smoothstep(-0.16, 0.06, el));
  var c = mix(hor, zen, pow(y, 0.6));

  // sun
  let sdot = clamp(dot(rd, sd), 0.0, 1.0);
  let sunUp = smoothstep(-0.14, 0.02, el);
  c += od_suncol(el) * pow(sdot, 5.0) * 0.32 * sunUp;
  c += od_suncol(el) * pow(sdot, 70.0) * 0.60 * sunUp;
  c += vec3f(5.2, 3.6, 2.0) * smoothstep(0.99972, 0.99990, sdot) * sunUp;

  // moon: cool disk + halo, out at night
  let mdot = clamp(dot(rd, md), 0.0, 1.0);
  let moonUp = night * smoothstep(-0.05, 0.10, md.y);
  c += vec3f(0.55, 0.62, 0.75) * pow(mdot, 90.0) * 0.5 * moonUp;
  c += vec3f(2.6, 2.8, 3.1) * smoothstep(0.99985, 0.99995, mdot) * moonUp;

  // stars + a faint galaxy band
  if (night > 0.02 && rd.y > 0.01) {
    let sp = rd.xz / (rd.y + 0.55) * 26.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let tw = 0.55 + 0.45 * sin(t * (0.8 + h) + h * 50.0);
    c += vec3f(0.72, 0.78, 0.95) * step(0.990, h) * smoothstep(0.30, 0.05, length(fract(sp) - 0.5)) * night * tw;
    let band = pow(max(1.0 - abs(rd.x * 0.8 + rd.y * 0.5 - 0.15), 0.0), 3.5);
    c += vec3f(0.07, 0.07, 0.12) * band * night * (0.5 + 0.3 * vnoise(sp * 0.5));
  }

  // clouds: sparse, tinted by the hour
  if (rd.y > 0.015) {
    let cp = rd.xz / (rd.y + 0.14) * 1.4 + vec2f(t * 0.006, t * 0.002);
    var cl = fbm(cp * 0.55, 4);
    cl = smoothstep(0.46, 0.78, cl);
    let cloudLit = mix(vec3f(0.06, 0.06, 0.10), mix(vec3f(1.15, 0.50, 0.28), vec3f(0.85, 0.85, 0.90), smoothstep(0.12, 0.5, el)), max(day, night * 0.12));
    c = mix(c, cloudLit, cl * 0.7 * smoothstep(0.015, 0.10, rd.y));
  }
  return c;
}

fn od_oct(uv0: vec2f, choppy: f32) -> f32 {
  let n = gnoise(uv0);
  let uv = uv0 + vec2f(n, n);
  var wv = 1.0 - abs(sin(uv));
  let swv = abs(cos(uv));
  wv = mix(wv, swv, wv);
  return pow(1.0 - pow(wv.x * wv.y, 0.65), choppy);
}

fn od_surge(pxz: vec2f, st: f32) -> f32 {
  let dr = length(pxz - od_ic());
  return exp(-max(dr - 5.8, 0.0) * 0.35) * (sin(st * 1.4 - dr * 0.9) * 0.5 + 0.62) * 1.05;
}


fn od_wake(pxz: vec2f) -> f32 {
  let d = vec2f(pxz.x - uni(7), pxz.y - 52.0);
  let along = -d.x * uni(8);                 // positive = behind the boat
  if (along < -3.0 || along > 26.0 || abs(d.y) > 12.0) { return 0.0; }
  let a = max(along, 0.0);
  var w = exp(-dot(d, d) * 0.35) * 0.8;      // bow mound at the hull
  let arm = exp(-pow((abs(d.y) - 0.36 * a) * 1.1, 2.0)) * exp(-a * 0.10);  // Kelvin arms (~19.5deg)
  let inside = smoothstep(0.36 * a + 1.0, 0.36 * a - 1.0, abs(d.y));
  let ripple = sin(a * 2.4) * 0.5 * inside * exp(-a * 0.13);               // transverse train
  return w + arm * 0.9 + ripple;
}

fn od_amp() -> f32 { return 0.55 + 0.75 * uni(3); }   // wind raises the sea


fn od_digiH(p: vec3f, st: f32, h0: f32) -> f32 {
  // DIGITAL: the sea quantizes into block columns, each cell stepping up and
  // down on its own clock — an equalizer where an ocean used to be.
  let u = uni(17);
  if (u <= 0.01) { return h0; }
  let cell = floor(p.xz / 2.0);
  let hsh = hash21(cell);
  let lvl = floor((0.5 + 0.5 * sin(st * (0.8 + hsh * 1.4) + hsh * 6.2831)) * 4.0 + 0.5);
  let bh = lvl * 0.55 - 0.4;
  return mix(h0, bh, u);
}

fn od_fireH(p: vec3f, st: f32, h0: f32) -> f32 {
  // TRANSITION: where the burn front has passed, the wave field morphs into
  // ANCHORED flame tongues — bases still in the world, only the lick alive.
  let u = uni(10);
  if (u <= 0.01) { return h0; }
  let front = smoothstep(u * 1.15, u * 1.15 - 0.22, fbm3(p.xz * 0.045 + vec2f(3.7, 0.0)));
  let burn = u * front;
  if (burn <= 0.003) { return h0; }
  var q = p.xz * 0.55;
  var f = 0.0;
  var amp2 = 1.0;
  for (var i = 0; i < 3; i++) {
    let n = vnoise(q + vec2f(f32(i) * 7.3, f32(i) * 3.1));
    f += (1.0 - abs(n * 2.0 - 1.0)) * amp2;
    q = q * 2.1;
    amp2 *= 0.45;
  }
  let flow = vnoise(p.xz * 1.4 + vec2f(0.0, -st * 3.2)) - 0.5;
  let pulse = 0.62 + 0.38 * sin(st * 6.5 + f * 11.0 + p.x * 1.3);
  let flameH = (f - 0.62) * 1.8 * pulse + flow * 0.35 * f;
  return mix(h0, max(flameH, h0 * 0.25), burn);
}

fn od_map3(p: vec3f, st: f32) -> f32 {
  var freq = 0.16;
  var amp = 0.6 * od_amp();
  var choppy = 4.0;
  var uv = p.xz;
  uv.x = uv.x * 0.75;
  var h = 0.0;
  for (var i = 0; i < 3; i++) {
    var d = od_oct((uv + vec2f(st)) * freq, choppy);
    d = d + od_oct((uv - vec2f(st)) * freq, choppy);
    h = h + d * amp;
    uv = mat2x2f(1.6, 1.2, -1.2, 1.6) * uv;
    freq = freq * 1.9;
    amp = amp * 0.22;
    choppy = mix(choppy, 1.0, 0.2);
  }
  h = h + od_surge(p.xz, st);
  h = h + od_wake(p.xz) * 0.22;
  h = od_fireH(p, st, h);
  h = od_digiH(p, st, h);
  return p.y - h;
}

fn od_map5(p: vec3f, st: f32) -> f32 {
  var freq = 0.16;
  var amp = 0.6 * od_amp();
  var choppy = 4.0;
  var uv = p.xz;
  uv.x = uv.x * 0.75;
  var h = 0.0;
  for (var i = 0; i < 5; i++) {
    var d = od_oct((uv + vec2f(st)) * freq, choppy);
    d = d + od_oct((uv - vec2f(st)) * freq, choppy);
    h = h + d * amp;
    uv = mat2x2f(1.6, 1.2, -1.2, 1.6) * uv;
    freq = freq * 1.9;
    amp = amp * 0.22;
    choppy = mix(choppy, 1.0, 0.2);
  }
  h = h + od_surge(p.xz, st);
  h = h + od_wake(p.xz) * 0.22;
  h = od_fireH(p, st, h);
  h = od_digiH(p, st, h);
  return p.y - h;
}

fn od_nrm(p: vec3f, eps: f32, st: f32) -> vec3f {
  let hy = od_map5(p, st);
  let hx = od_map5(p + vec3f(eps, 0.0, 0.0), st);
  let hz = od_map5(p + vec3f(0.0, 0.0, eps), st);
  return normalize(vec3f(hx - hy, eps, hz - hy));
}

fn od_spec(n: vec3f, l: vec3f, e: vec3f, s: f32) -> f32 {
  let nrm = (s + 8.0) / (3.14159 * 8.0);
  return pow(max(dot(reflect(e, n), l), 0.0), s) * nrm;
}

fn od_seacol(p: vec3f, n: vec3f, sd: vec3f, md: vec3f, eye: vec3f, dist: vec3f, t: f32, st: f32) -> vec3f {
  let el = uni(1);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);

  var fres = clamp(1.0 - dot(n, -eye), 0.0, 1.0);
  fres = pow(fres, 3.0) * 0.5;

  let reflected = od_sky(reflect(eye, n), sd, md, t);
  let base = mix(vec3f(0.004, 0.008, 0.016), vec3f(0.035, 0.06, 0.11), day);
  let waterCol = vec3f(0.17, 0.23, 0.22) * (0.25 + 0.75 * day);
  let refracted = base + pow(dot(n, sd) * 0.4 + 0.6, 80.0) * waterCol * 0.12 * day;

  var col = mix(refracted, reflected, fres);

  let atten = max(1.0 - dot(dist, dist) * 0.001, 0.0);
  col = col + waterCol * (p.y - 0.6) * 0.18 * atten;

  // sun glitter by day, moon glitter by night — same sea, different star
  col = col + od_suncol(el) * vec3f(2.4, 1.5, 0.8) * od_spec(n, sd, eye, 90.0) * smoothstep(-0.08, 0.05, el);
  col = col + vec3f(0.9, 1.05, 1.3) * od_spec(n, md, eye, 140.0) * night * smoothstep(0.0, 0.15, md.y) * 1.6;

  // crest foam
  let foamN = vnoise(p.xz * 2.2 + vec2f(t * 0.5, -t * 0.35));
  let crest = smoothstep(1.05, 1.55, p.y) * smoothstep(0.42, 0.85, foamN);
  col = mix(col, vec3f(0.90, 0.82, 0.72) * (0.25 + 0.75 * day), crest * atten * 0.4);

  // island surf ring
  let drf = length(p.xz - od_ic()) - 6.2;
  let ph = sin(st * 1.4 - (drf + 6.2) * 0.9) * 0.5 + 0.5;
  var rockFoam = smoothstep(3.2, 0.2, drf) * (0.35 + 0.65 * ph);
  rockFoam = rockFoam * (0.45 + 0.55 * vnoise(p.xz * 2.6 + vec2f(st * 0.8, -st * 0.55)));
  col = mix(col, vec3f(0.90, 0.88, 0.84) * (0.3 + 0.7 * day + 0.25 * night), clamp(rockFoam, 0.0, 1.0) * 0.85);

  // boat wake foam — the ocean reads the boat off the whiteboard
  let wk = od_wake(p.xz);
  col = mix(col, vec3f(0.82, 0.85, 0.84) * (0.35 + 0.65 * day + 0.2 * night), clamp(wk * 0.9 - 0.12, 0.0, 1.0) * 0.55);

  return col;
}

fn visual_od_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x, -uv.y);
  let t = time;
  let st = 1.0 + t * 0.8;

  let bob = sin(t * 0.5) * 0.06;
  let ro = vec3f(0.0, 3.4 + bob, 0.0);
  // wide viewports crop the field vertically — widen the vertical FOV to keep
  // the whole lighthouse in frame at any aspect
  let visH = clamp(frame.resolution.y / max(frame.resolution.x, 1.0), 0.45, 1.0);
  var rd = normalize(vec3f(p.x, (p.y * 0.72) / visH - 0.14 * visH, 1.75));
  let rxy = rotate(rd.xy, sin(t * 0.35) * 0.012);
  rd = normalize(vec3f(rxy.x, rxy.y, rd.z));

  // the whiteboard drives the world
  let saz = uni(0);
  let sel = uni(1);
  let sd = normalize(vec3f(cos(saz) * cos(sel), sin(sel), sin(saz) * cos(sel)));
  let mel = uni(5);
  let maz = uni(6);
  let md = normalize(vec3f(cos(maz) * cos(mel), sin(mel), sin(maz) * cos(mel)));

  var col = od_sky(rd, sd, md, t);
  var tScene = 100000.0;

  // ---- ocean ----
  if (rd.y < 0.0) {
    var tm = 0.0;
    var tx = 1000.0;
    var hx = od_map3(ro + rd * tx, st);
    if (hx < 0.0) {
      var hm = od_map3(ro, st);
      var tmid = 0.0;
      for (var i = 0; i < 8; i++) {
        tmid = mix(tm, tx, hm / (hm - hx));
        let pm = ro + rd * tmid;
        let hmid = od_map3(pm, st);
        if (hmid < 0.0) { tx = tmid; hx = hmid; } else { tm = tmid; hm = hmid; }
      }
      let pt = ro + rd * tmid;
      let dist = pt - ro;
      let eps = max(dot(dist, dist) * 0.0002, 0.002);
      let n = od_nrm(pt, eps, st);
      var seaCol = od_seacol(pt, n, sd, md, rd, dist, t, st);
      if (uni(10) > 0.01) {
        let u = uni(10);
        // a patchy ignition front spreads across the water
        let front = smoothstep(u * 1.15, u * 1.15 - 0.22, fbm3(pt.xz * 0.045 + 3.7));
        let burn = u * front;
        if (burn > 0.003) {
          // char: the water darkens as it heats
          seaCol = mix(seaCol, seaCol * vec3f(0.35, 0.22, 0.18), min(burn * 2.2, 1.0));
          // ember cracks glow in the troughs
          let crack = pow(vnoise(pt.xz * 1.6 + vec2f(st * 0.4, -st * 0.3)), 4.0);
          seaCol += vec3f(2.4, 0.5, 0.05) * crack * smoothstep(0.05, 0.45, burn);
          // crests ignite: flames ride the wave tops
          let crest = smoothstep(0.4, 1.4, pt.y);
          let lick = fbm3(vec2f(pt.x * 0.8, pt.z * 0.8 - t * 2.6));
          seaCol += mix(vec3f(1.8, 0.5, 0.02), vec3f(3.0, 1.8, 0.25), lick) * crest * smoothstep(0.3, 0.8, burn) * (0.6 + 0.4 * lick);
          // FIRE, not magma: color climbs the wave — white-gold roots,
          // orange body, red tips licking into soot
          let hgt = clamp(pt.y * 0.55 + 0.35, 0.0, 1.3);
          let waver = fbm3(vec2f(pt.x * 1.1, pt.z * 1.1 - t * 3.4));
          var flame = mix(vec3f(3.4, 2.6, 1.1), vec3f(2.6, 1.0, 0.12), clamp(hgt, 0.0, 1.0));
          flame = mix(flame, vec3f(0.9, 0.16, 0.04), smoothstep(0.9, 1.3, hgt + waver * 0.3));
          let flicker = 0.75 + 0.25 * sin(t * 11.0 + pt.x * 2.2 + waver * 8.0);
          seaCol = mix(seaCol, flame * flicker, smoothstep(0.35, 0.9, burn) * (0.55 + 0.45 * waver));
        }
      }
      if (uni(17) > 0.01) {
        let u2 = uni(17);
        let cell2 = floor(pt.xz / 2.0);
        let f2 = fract(pt.xz / 2.0);
        let hsh2 = hash21(cell2);
        let e2 = max(smoothstep(0.40, 0.49, abs(f2.x - 0.5)), smoothstep(0.40, 0.49, abs(f2.y - 0.5)));
        let pulse2 = 0.5 + 0.5 * sin(st * 2.0 + hsh2 * 6.2831);
        var digi = mix(vec3f(0.015, 0.04, 0.07), vec3f(0.0, 0.30, 0.40), pulse2 * 0.6);
        digi += vec3f(0.1, 1.8, 2.2) * e2 * (0.45 + 0.55 * pulse2);
        digi += vec3f(1.6, 0.4, 2.0) * step(0.86, hsh2) * pulse2 * 0.8;
        seaCol = mix(seaCol, digi, u2);
      }
      let seaBlend = pow(1.0 - smoothstep(-0.02, 0.0, rd.y), 0.2);
      col = mix(col, seaCol, seaBlend);
      tScene = tmid;
    }
  }

  // leaping tongues — the burn climbs off the water into the air
  if (uni(10) > 0.05 && rd.y < 0.16) {
    let hb = smoothstep(0.16, -0.02, rd.y);
    let fx = rd.x / max(rd.z, 0.2);
    let tongue = fbm3(vec2f(fx * 9.0, rd.y * 26.0 - t * 3.2));
    let tongue2 = vnoise(vec2f(fx * 22.0 + 7.0, rd.y * 40.0 - t * 5.0));
    let leap = pow(tongue, 2.0) * (0.5 + 0.5 * tongue2) * hb * uni(10);
    col += mix(vec3f(2.2, 0.6, 0.04), vec3f(3.4, 1.9, 0.3), tongue2) * leap * 0.9;
  }

  // ---- distant sailboat crossing (whiteboard position) ----
  let B = vec3f(uni(7), 0.9 + sin(t * 0.7) * 0.15, 52.0);
  let toB = B - ro;
  let bDist = length(toB);
  let bDir = toB / bDist;
  if (dot(rd, bDir) > 0.995 && tScene > bDist) {
    let right = normalize(cross(bDir, vec3f(0.0, 1.0, 0.0)));
    let upv = cross(right, bDir);
    let par = dot(rd, bDir);
    let lx = dot(rd, right) / par * bDist * uni(8);   // flip with travel direction
    let ly = dot(rd, upv) / par * bDist;
    // hull + mainsail silhouette, warm-rimmed at low sun
    let hull = max(abs(lx) - 1.9 * (1.0 - clamp(ly + 0.4, 0.0, 0.5)), abs(ly + 0.45) - 0.35);
    let sail = max(max(-(lx + 0.1), ly - 2.6), (lx * 0.62 + ly * 0.55) - 1.35);
    let el2 = uni(1);
    let silCol = mix(vec3f(0.015, 0.015, 0.025), vec3f(0.10, 0.05, 0.04), smoothstep(0.3, 0.02, abs(el2)) * 0.8);
    if (hull < 0.0 || sail < 0.0) {
      col = silCol + od_suncol(el2) * 0.25 * smoothstep(0.15, -0.05, lx * uni(8)) * smoothstep(-0.08, 0.05, el2);
    }
  }

  // selection outline: the lighthouse is a thing you can pick up
  if (uni(13) > 0.05) {
    let od = abs(sdRoundedBox(p - vec2f(uni(14), uni(15)), vec2f(uni(16) * 0.5, uni(16)), 0.03));
    col += vec3f(1.1, 0.95, 0.5) * smoothstep(0.012, 0.0, od) * uni(13) * (0.65 + 0.35 * sin(t * 4.0));
  }

  return vec4f(col, 1.0);
}

fn od2_ic() -> vec2f { return vec2f(uni(11), uni(12)); }
fn od2_suncol(el: f32) -> vec3f {
  return mix(vec3f(1.30, 0.45, 0.16), vec3f(1.15, 1.05, 0.90), smoothstep(0.02, 0.55, el));
}
fn od2_box(p: vec3f, b: vec3f) -> f32 {
  let d = abs(p) - b;
  return length(max(d, vec3f(0.0))) + min(max(d.x, max(d.y, d.z)), 0.0);
}

// materials: 0 rock · 1 whitewash tower · 2 ironwork · 3 lantern glass
//            4 copper cupola · 5 cottage wall · 6 cottage roof · 7 chimney · 8 door
fn od2_sdf(p: vec3f) -> vec2f {
  let ic = od2_ic();
  let q = p - vec3f(ic.x, 0.0, ic.y);

  // the rock
  var d = length(q * vec3f(1.0, 1.25, 1.08)) - 6.4;
  d = d - (vnoise3(q * 0.55) - 0.5) * 2.6 - (vnoise3(q * 1.9) - 0.5) * 0.9;
  var m = 0.0;

  // tapered masonry tower with a wider plinth — colonial whitewash
  let ty = clamp((p.y - 4.0) / 7.5, 0.0, 1.0);
  let taper = mix(1.42, 0.88, pow(ty, 0.85));
  let plinth = 1.0 + 0.35 * smoothstep(5.2, 4.0, p.y);
  let dTower = max(length(q.xz) - taper * plinth, abs(p.y - 7.75) - 3.75);
  if (dTower < d) { d = dTower; m = 1.0; }

  // gallery deck + railing: handrail ring and a circle of balusters
  let dDeck = max(length(q.xz) - 1.52, abs(p.y - 11.62) - 0.14);
  if (dDeck < d) { d = dDeck; m = 2.0; }
  let dRail = max(abs(length(q.xz) - 1.44) - 0.035, abs(p.y - 12.42) - 0.045);
  if (dRail < d) { d = dRail; m = 2.0; }
  let phi = atan2(q.z, q.x);
  let seg = 6.28318 / 20.0;
  let aphi = (glsl_mod(phi + seg * 0.5, seg) - seg * 0.5) * 1.44;
  let dBal = max(length(vec2f(length(q.xz) - 1.44, aphi)) - 0.035, abs(p.y - 12.02) - 0.42);
  if (dBal < d) { d = dBal; m = 2.0; }

  // octagonal lantern room
  var oct = abs(q.x);
  oct = max(oct, abs(q.z));
  oct = max(oct, abs(q.x * 0.7071 + q.z * 0.7071));
  oct = max(oct, abs(q.x * 0.7071 - q.z * 0.7071));
  let dLan = max(oct - 0.82, abs(p.y - 12.55) - 0.72);
  if (dLan < d) { d = dLan; m = 3.0; }

  // copper cupola with finial
  let ry = clamp((p.y - 13.27) / 1.15, 0.0, 1.0);
  let dRoof = max(length(q.xz) - mix(1.06, 0.06, pow(ry, 0.72)), abs(p.y - 13.84) - 0.58);
  if (dRoof < d) { d = dRoof; m = 4.0; }
  let dFin = length(vec3f(q.x, (p.y - 14.72) * 0.8, q.z)) - 0.14;
  if (dFin < d) { d = dFin; m = 2.0; }

  // the keeper's cottage: clapboard saltbox, gable roof, brick chimney
  let qc = q - vec3f(3.1, 4.45, 0.6);
  let dHouse = od2_box(qc, vec3f(1.55, 0.95, 1.15));
  if (dHouse < d) { d = dHouse; m = 5.0; }
  let dRoofH = max(max(abs(qc.z) * 0.92 + (qc.y - 1.72), -(qc.y - 0.75)), max(abs(qc.x) - 1.72, abs(qc.z) - 1.32));
  if (dRoofH < d) { d = dRoofH; m = 6.0; }
  let dChim = od2_box(qc - vec3f(0.55, 1.85, 0.0), vec3f(0.22, 0.65, 0.22));
  if (dChim < d) { d = dChim; m = 7.0; }

  return vec2f(d, m);
}

fn od2_trace(ro: vec3f, rd: vec3f) -> vec3f {
  let ic = od2_ic();
  let oc = ro - vec3f(ic.x, 6.5, ic.y);
  let b = dot(oc, rd);
  let c = dot(oc, oc) - 182.25;
  let disc = b * b - c;
  if (disc < 0.0) { return vec3f(0.0, 0.0, -1.0); }
  let sq = sqrt(disc);
  let t1 = -b + sq;
  var tt = max(-b - sq, 0.0);
  for (var i = 0; i < 60; i++) {
    let dm = od2_sdf(ro + rd * tt);
    if (dm.x < 0.02) { return vec3f(tt, dm.y, 1.0); }
    tt = tt + dm.x * 0.7;
    if (tt > t1) { break; }
  }
  return vec3f(0.0, 0.0, -1.0);
}

// arched-window mask on the tower shaft, facing the sea (toward the viewer)
fn od2_window(phi: f32, y: f32, yc: f32) -> f32 {
  let PHIC = -1.296;   // bearing from island to the home shore
  var ang = phi - PHIC;
  ang = glsl_mod(ang + 3.14159, 6.28318) - 3.14159;
  let aw = ang * 1.15;
  let wy = y - yc;
  let rect = step(abs(aw), 0.145) * step(-0.26, wy) * step(wy, 0.13);
  let arch = step(length(vec2f(aw, wy - 0.13)), 0.145);
  return max(rect, arch);
}

fn od2_shade(p: vec3f, n: vec3f, rd: vec3f, m: f32, sd: vec3f, t: f32, st: f32) -> vec3f {
  let el = uni(1);
  let day = smoothstep(-0.10, 0.35, el);
  let night = smoothstep(0.05, -0.18, el);
  let ic = od2_ic();
  let q = p - vec3f(ic.x, 0.0, ic.y);
  let phi = atan2(q.z, q.x);
  var alb = vec3f(0.0);
  var emis = vec3f(0.0);
  var spec = 0.0;

  if (m < 0.5) {
    // rock: strata, wet dark base, lichen where it faces the sky
    let strat = sin(p.y * 2.1 + (vnoise3(p * 0.4) - 0.5) * 5.0);
    alb = mix(vec3f(0.055, 0.052, 0.058), vec3f(0.125, 0.115, 0.10), 0.5 + 0.5 * strat);
    alb = mix(alb, vec3f(0.14, 0.13, 0.10), vnoise3(p * 1.7) * 0.4);
    let wet = smoothstep(2.6, 0.5, p.y);
    alb = alb * (1.0 - wet * 0.6);
    spec = wet * 0.5;
    let lich = smoothstep(0.45, 0.75, vnoise3(p * 2.3)) * smoothstep(0.35, 0.7, n.y) * smoothstep(3.2, 4.4, p.y);
    alb = mix(alb, vec3f(0.16, 0.17, 0.08), lich * 0.7);
  } else if (m < 1.5) {
    // whitewashed masonry: courses, joints, weather streaks
    alb = vec3f(0.86, 0.85, 0.81);
    let course = smoothstep(0.055, 0.02, abs(fract(p.y / 0.58) - 0.5) * 0.58);
    let joint = smoothstep(0.05, 0.02, abs(fract(phi * 1.15 / 0.85 + floor(p.y / 0.58) * 0.5) - 0.5) * 0.85);
    alb = alb * (1.0 - course * 0.10 - joint * course * 0.05);
    let streak = smoothstep(0.55, 0.9, vnoise(vec2f(phi * 6.0, p.y * 0.22)));
    alb = alb * (1.0 - streak * 0.16 * smoothstep(4.5, 10.5, p.y));
    alb = alb * (1.0 - smoothstep(5.4, 4.2, p.y) * 0.18);   // grime at the plinth
    // three arched windows climbing the shaft + the door
    var win = 0.0;
    win = max(win, od2_window(phi, p.y, 6.3));
    win = max(win, od2_window(phi, p.y, 8.5));
    win = max(win, od2_window(phi, p.y, 10.5));
    let doorM = od2_window(phi, p.y * 0.72, 3.42);
    alb = mix(alb, vec3f(0.05, 0.05, 0.06), win);
    alb = mix(alb, vec3f(0.06, 0.13, 0.09), doorM);        // colonial green door
    let lit = 0.35 + 0.65 * smoothstep(0.4, 0.9, hash11(floor(p.y / 2.0)));
    emis = emis + vec3f(2.0, 1.25, 0.45) * win * night * lit;
  } else if (m < 2.5) {
    alb = vec3f(0.055, 0.058, 0.068);   // wrought iron
    spec = 0.35;
  } else if (m < 3.5) {
    // lantern glazing: mullions read dark, panes catch sky and hold the lamp
    let mseg = 6.28318 / 8.0;
    let mphi = abs(glsl_mod(phi + mseg * 0.5, mseg) - mseg * 0.5);
    let mull = step(mphi, 0.09);
    let bands = step(abs(p.y - 12.55), 0.06) + step(0.60, abs(p.y - 12.55));
    if (mull + bands > 0.5) {
      alb = vec3f(0.055, 0.058, 0.068);
      spec = 0.35;
    } else {
      alb = vec3f(0.02, 0.025, 0.035);
      spec = 1.2;
      let lampP = vec3f(ic.x, 12.55, ic.y);
      let lampD = length(p - lampP);
      emis = vec3f(6.5, 4.9, 2.6) * exp(-lampD * lampD * 0.9) * (0.15 + 0.85 * uni(4)) * 2.2;
      emis = emis + vec3f(1.4, 1.05, 0.55) * (0.10 + 0.90 * uni(4)) * 0.35;
    }
  } else if (m < 4.5) {
    // copper gone to patina
    let pat = vnoise3(p * 3.1);
    alb = mix(vec3f(0.30, 0.20, 0.12), vec3f(0.24, 0.40, 0.33), smoothstep(0.35, 0.7, pat));
    spec = 0.6;
  } else if (m < 5.5) {
    // clapboard: fine horizontal shadow lines
    alb = vec3f(0.82, 0.80, 0.74);
    let lap = smoothstep(0.10, 0.02, abs(fract(p.y / 0.16) - 0.5) * 0.16);
    alb = alb * (1.0 - lap * 0.13);
    // two warm windows on the seaward face
    let qc = q - vec3f(3.1, 4.45, 0.6);
    let front = step(qc.z, -1.05);
    let wmask = front * step(abs(abs(qc.x) - 0.62), 0.26) * step(abs(qc.y + 0.05), 0.30);
    alb = mix(alb, vec3f(0.05, 0.05, 0.06), wmask);
    emis = emis + vec3f(2.2, 1.35, 0.5) * wmask * night;
  } else if (m < 6.5) {
    alb = vec3f(0.16, 0.15, 0.15) * (0.8 + 0.4 * vnoise(vec2f(p.x * 6.0, p.z * 6.0)));  // shingles
  } else if (m < 7.5) {
    let brick = smoothstep(0.06, 0.02, abs(fract(p.y / 0.14) - 0.5) * 0.14);
    alb = vec3f(0.38, 0.16, 0.11) * (1.0 - brick * 0.35);   // brick chimney
  } else {
    alb = vec3f(0.06, 0.13, 0.09);
  }

  let dif = max(dot(n, sd), 0.0) * smoothstep(-0.05, 0.05, el);
  let ambSky = mix(vec3f(0.05, 0.06, 0.10), vec3f(0.30, 0.34, 0.48), day) * (0.35 + 0.25 * max(n.y, 0.0));
  let sunCol = od2_suncol(el) * 1.4;
  var col = alb * (ambSky + sunCol * dif);
  col = col + alb * vec3f(0.10, 0.12, 0.17) * max(dot(n, vec3f(0.3, 0.8, -0.5)), 0.0) * night;
  let rim = pow(clamp(1.0 + dot(rd, n), 0.0, 1.0), 3.0);
  col = col + sunCol * rim * 0.15 * day;
  col = col + sunCol * pow(max(dot(reflect(rd, n), sd), 0.0), 24.0) * spec * day;

  if (m < 0.5) {
    let surgePh = max(sin(st * 1.4), 0.0);
    let sprayN = vnoise(vec2f(p.x * 1.3 + p.z * 1.1, p.y * 1.8) + vec2f(st * 0.9, -st * 0.6));
    let spray = smoothstep(2.1, 0.9, p.y) * smoothstep(0.35, 0.9, sprayN) * (0.4 + 0.6 * surgePh);
    col = mix(col, vec3f(0.88, 0.90, 0.92) * (0.3 + 0.7 * day + 0.3 * night), clamp(spray, 0.0, 1.0) * 0.45);
  }
  return col + emis;
}

fn visual_od_lh(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x, -uv.y);
  let t = time;
  let st = 1.0 + t * 0.8;

  // the same eye as the world field — the two compose pixel-perfectly
  let bob = sin(t * 0.5) * 0.06;
  let ro = vec3f(0.0, 3.4 + bob, 0.0);
  // wide viewports crop the field vertically — widen the vertical FOV to keep
  // the whole lighthouse in frame at any aspect
  let visH = clamp(frame.resolution.y / max(frame.resolution.x, 1.0), 0.45, 1.0);
  var rd = normalize(vec3f(p.x, (p.y * 0.72) / visH - 0.14 * visH, 1.75));
  let rxy = rotate(rd.xy, sin(t * 0.35) * 0.012);
  rd = normalize(vec3f(rxy.x, rxy.y, rd.z));

  let saz = uni(0);
  let sel = uni(1);
  let sd = normalize(vec3f(cos(saz) * cos(sel), sin(sel), sin(saz) * cos(sel)));

  var col = behind.rgb;

  // the sea is not ours, but it still hides our feet: approximate the water
  // plane so rock below a swell yields to the world behind
  var tSea = 100000.0;
  if (rd.y < -0.001) { tSea = (0.85 - ro.y) / rd.y; }

  let lh = od2_trace(ro, rd);
  var tScene = 100000.0;
  if (lh.z > 0.0) {
    let pr = ro + rd * lh.x;
    let e = 0.03;
    let d0 = od2_sdf(pr).x;
    let nr = normalize(vec3f(
      od2_sdf(pr + vec3f(e, 0.0, 0.0)).x - d0,
      od2_sdf(pr + vec3f(0.0, e, 0.0)).x - d0,
      od2_sdf(pr + vec3f(0.0, 0.0, e)).x - d0));
    var sc = od2_shade(pr, nr, rd, lh.y, sd, t, st);
    sc = mix(sc, vec3f(0.45, 0.33, 0.30) * (0.2 + 0.8 * smoothstep(-0.1, 0.3, uni(1))), clamp(lh.x * 0.004, 0.0, 0.4));
    // the lighthouse holds NO opacity: it is glass over the sea. The world
    // behind always breathes through it, and the more the water changes
    // state, the more the effect pours through the structure itself.
    let stateI = clamp(max(uni(10), uni(17)), 0.0, 1.0);
    let veilTop = mix(1.15, 3.4, stateI);
    let waterVeil = smoothstep(veilTop, 0.45, pr.y);
    let ghost = mix(0.30, 0.60, stateI);
    col = mix(sc, behind.rgb, clamp(max(waterVeil, ghost), 0.0, 1.0));
    tScene = lh.x;
  }

  // ── the beam as a force field: hard-edged cone, diagonal energy hatch ──
  let beamI = uni(4);
  if (beamI > 0.01) {
    let ic = od2_ic();
    let lamp = vec3f(ic.x, 12.55, ic.y);
    for (var k = 0; k < 2; k++) {
      let ba = uni(9) + f32(k) * 3.14159;
      let Ld = normalize(vec3f(cos(ba), -0.02, sin(ba)));
      let w0 = ro - lamp;
      let a1 = dot(rd, Ld);
      let b1 = dot(rd, w0);
      let c1 = dot(Ld, w0);
      let den = 1.0 - a1 * a1;
      if (den > 0.0001) {
        let sRay = (a1 * c1 - b1) / den;
        let sBeam = (c1 - a1 * b1) / den;
        if (sRay > 0.0 && sRay < min(tScene, tSea) && sBeam > 1.2) {
          let dd = length((ro + rd * sRay) - (lamp + Ld * sBeam));
          let w = 0.32 + sBeam * 0.035;            // the cone opens with distance
          let shell = smoothstep(w, w * 0.78, dd); // hard wall, not a gaussian
          let edge = exp(-pow((dd - w * 0.92) * 5.5, 2.0)) * 0.8;   // bright skin
          // one family of diagonal interference — a field, not a net
          let hatch = pow(0.5 + 0.5 * sin(sBeam * 2.2 - dd * 7.0 - t * 6.0), 3.0);
          let breathe = 0.93 + 0.07 * sin(t * 22.0 + sBeam * 0.7);
          let body = shell * (0.34 + 0.66 * hatch);
          let fall = exp(-sBeam * 0.042);
          // when the beam points at the eye its cross-section is half the sky — dim it
          let headOn = 1.0 - pow(abs(a1), 10.0);
          col = col + mix(vec3f(2.5, 1.95, 1.15), vec3f(3.1, 2.95, 2.45), shell * hatch)
                      * (body + edge) * fall * 1.5 * beamI * breathe * headOn;
        }
      }
    }
    // lamp flare when the beam sweeps you
    let toLamp = lamp - ro;
    let lampDist = length(toLamp);
    let ba0 = uni(9);
    let alignK = pow(abs(dot(vec2f(cos(ba0), sin(ba0)), normalize(ro.xz - lamp.xz))), 24.0);
    let flare = pow(max(dot(rd, toLamp / lampDist), 0.0), 700.0);
    col = col + vec3f(4.5, 3.4, 2.0) * flare * (0.5 + 4.5 * alignK) * beamI;
  }

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = behind.rgb; }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}

fn visual_od_flies(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  // fireflies over the island after dark — existence itself read off the whiteboard
  let night = smoothstep(0.02, -0.14, uni(1));
  if (night < 0.02) { return vec4f(0.0); }
  let wind = uni(3);
  var c = vec3f(0.0);
  var a = 0.0;
  for (var i = 0; i < 18; i++) {
    let fi = f32(i);
    let h1 = hash11(fi * 13.7);
    let h2 = hash11(fi * 29.3);
    // hover around the island (screen left), drift on the wind
    var pos = vec2f(-0.55 + (h1 - 0.5) * 0.55, -0.10 + (h2 - 0.5) * 0.38);
    pos.x += sin(time * (0.20 + h1 * 0.25) + fi * 2.4) * 0.06 + wind * 0.02;
    pos.y += cos(time * (0.16 + h2 * 0.22) + fi * 1.7) * 0.045;
    let d2 = dot(uv - pos, uv - pos);
    let blink = smoothstep(0.25, 0.9, 0.5 + 0.5 * sin(time * (0.7 + h1 * 1.3) + fi * 5.0));
    let g = exp(-d2 * 26000.0) * blink;
    c += vec3f(2.2, 1.55, 0.45) * g;
    c += vec3f(0.9, 0.6, 0.15) * exp(-d2 * 2600.0) * blink * 0.35;
    a = max(a, clamp(g * 1.6 + exp(-d2 * 2600.0) * 0.3, 0.0, 1.0));
  }
  return vec4f(c * night, a * night * 0.95);
}

const NC_CELL: f32 = 9.0;

struct NCHit { t: f32, kind: i32, n: vec3f, cell: vec2f };

fn nc_mode() -> f32 { return uni(15); }   // 0 endless · 1 district

fn nc_isStreet(cell: vec2f) -> bool {
  if (nc_mode() > 0.5) {                  // district: finite table, open beyond
    if (cell.x < -5.5 || cell.x > 4.5 || cell.y < -5.5 || cell.y > 4.5) { return true; }
  }
  if (cell.x == 0.0) { return true; }
  if (abs(cell.y - 5.0 * round(cell.y / 5.0)) < 0.5) { return true; }
  return false;
}

fn nc_dims(cell: vec2f) -> vec3f {
  let r = hash22(cell);
  let h  = 6.0 + r.x * 40.0;
  let bw = NC_CELL * 0.5 * (0.72 + r.y * 0.20);
  let bd = NC_CELL * 0.5 * (0.72 + fract(r.y * 7.31 + r.x) * 0.20);
  return vec3f(h, bw, bd);
}

fn nc_ball() -> vec3f { return vec3f(uni(1), uni(2), uni(3)); }

fn nc_sphereT(ro: vec3f, rd: vec3f, c: vec3f, r: f32) -> f32 {
  let oc = ro - c;
  let b = dot(oc, rd);
  let cc = dot(oc, oc) - r * r;
  let h = b * b - cc;
  if (h < 0.0) { return -1.0; }
  return -b - sqrt(h);
}

fn nc_traceCity(ro: vec3f, rd: vec3f, maxd: f32, maxCells: i32) -> NCHit {
  var best: NCHit;
  best.t = maxd; best.kind = -1; best.n = vec3f(0.0, 1.0, 0.0); best.cell = vec2f(0.0, 0.0);

  if (rd.y < -1.0e-4) {
    let tg = -ro.y / rd.y;
    if (tg > 0.0 && tg < best.t) { best.t = tg; best.kind = 0; best.n = vec3f(0.0, 1.0, 0.0); }
  }

  var cell = floor(vec2f(ro.x, ro.z) / NC_CELL);
  let stepDir = sign(vec2f(rd.x, rd.z));
  let cellMin = cell * NC_CELL;

  var tMaxX = 1.0e9;  var tMaxZ = 1.0e9;
  var tDeltaX = 1.0e9; var tDeltaZ = 1.0e9;
  if (abs(rd.x) > 1.0e-6) {
    let bx = select(cellMin.x, cellMin.x + NC_CELL, rd.x > 0.0);
    tMaxX = (bx - ro.x) / rd.x;   tDeltaX = NC_CELL / abs(rd.x);
  }
  if (abs(rd.z) > 1.0e-6) {
    let bz = select(cellMin.y, cellMin.y + NC_CELL, rd.z > 0.0);
    tMaxZ = (bz - ro.z) / rd.z;   tDeltaZ = NC_CELL / abs(rd.z);
  }

  var tEnter = 0.0;
  for (var k = 0; k < maxCells; k = k + 1) {
    if (!nc_isStreet(cell)) {
      let dm = nc_dims(cell);
      let c = vec3f((cell.x + 0.5) * NC_CELL, dm.x * 0.5, (cell.y + 0.5) * NC_CELL);
      let half = vec3f(dm.y, dm.x * 0.5, dm.z);
      let m = 1.0 / rd;
      let nrm = m * (ro - c);
      let kk = abs(m) * half;
      let t1 = -nrm - kk;
      let t2 = -nrm + kk;
      let tN = max(max(t1.x, t1.y), t1.z);
      let tF = min(min(t2.x, t2.y), t2.z);
      if (tF >= tN && tF > 0.0) {
        let th = select(tN, 0.001, tN < 0.0);
        if (th < best.t) {
          best.t = th; best.kind = 1; best.cell = cell;
          best.n = -sign(rd) * step(t1.yzx, t1.xyz) * step(t1.zxy, t1.xyz);
        }
      }
    }
    if (tMaxX < tMaxZ) { tEnter = tMaxX; tMaxX = tMaxX + tDeltaX; cell.x = cell.x + stepDir.x; }
    else              { tEnter = tMaxZ; tMaxZ = tMaxZ + tDeltaZ; cell.y = cell.y + stepDir.y; }
    if (tEnter > best.t || tEnter > maxd) { break; }
  }
  return best;
}

fn nc_sky(rd: vec3f) -> vec3f {
  let y = max(rd.y, 0.0);
  var c = mix(vec3f(0.050, 0.060, 0.110), vec3f(0.008, 0.012, 0.035), pow(y, 0.5));
  c += vec3f(0.28, 0.13, 0.05) * exp(-max(rd.y, 0.0) * 5.5);
  let md = normalize(vec3f(-0.45, 0.42, 1.0));
  let m = max(dot(rd, md), 0.0);
  c += vec3f(0.90, 0.92, 0.98) * pow(m, 3000.0) * 3.0;
  c += vec3f(0.30, 0.34, 0.44) * pow(m, 30.0) * 0.35;
  if (rd.y > 0.05) {
    let sp = rd.xz / (rd.y + 0.2);
    let stars = hash21(floor(sp * 40.0));
    c += vec3f(step(0.995, stars)) * 0.8 * smoothstep(0.05, 0.30, rd.y);
  }
  return c;
}

fn nc_facade(p: vec3f, n: vec3f, cell: vec2f) -> vec3f {
  let baseCol = vec3f(0.018, 0.022, 0.035);
  if (abs(n.y) > 0.55) { return vec3f(0.012, 0.016, 0.026); }
  var u = p.z;
  if (abs(n.z) > abs(n.x)) { u = p.x; }
  let WU = 1.05;  let WV = 1.35;
  let cu = floor(u / WU);
  let cv = floor((p.y - 0.6) / WV);
  let fu = fract(u / WU);
  let fv = fract((p.y - 0.6) / WV);
  let inWin = step(0.18, fu) * step(fu, 0.82) * step(0.20, fv) * step(fv, 0.86) * step(0.6, p.y);
  let r = hash21(cell * 7.0 + vec2f(cu * 1.3, cv * 2.1));
  let lit = step(0.48, r);
  let cyan = step(0.86, hash21(cell + vec2f(cu, cv) * 0.7));
  let wc = mix(vec3f(1.70, 1.20, 0.62), vec3f(0.45, 1.50, 1.80), cyan);
  return baseCol + wc * lit * inWin * 2.4;
}

fn nc_ballBody(flash: f32) -> vec3f {
  return mix(vec3f(3.0, 1.7, 0.8), vec3f(7.0, 5.5, 4.0), flash);
}

fn nc_ballGlow(ro: vec3f, rd: vec3f, ball: vec3f, sceneT: f32, flash: f32) -> vec3f {
  let oc = ball - ro;
  let tca = dot(oc, rd);
  if (tca < 0.0) { return vec3f(0.0); }
  let d2x = dot(oc, oc) - tca * tca;
  // occluded: a faint pulse bleeds through the towers — the toy is never lost
  if (tca > sceneT + 2.0) { return vec3f(1.3, 0.55, 0.28) * exp(-d2x * 0.030) * (0.12 + flash * 0.3); }
  let d2 = dot(oc, oc) - tca * tca;
  let trail = ball - normalize(vec3f(uni(5), uni(6), uni(7)) + vec3f(1.0e-5)) * 2.4;
  let oc2 = trail - ro;
  let tca2 = dot(oc2, rd);
  var g = exp(-d2 * 0.10) * (0.8 + flash * 1.6);
  if (tca2 > 0.0 && tca2 < sceneT + 2.0) {
    g += exp(-(dot(oc2, oc2) - tca2 * tca2) * 0.16) * 0.30;
  }
  return vec3f(1.7, 1.0, 0.5) * g;
}

fn nc_reflColor(ro: vec3f, rd: vec3f, ball: vec3f, flash: f32) -> array<vec3f, 2> {
  let hb = nc_traceCity(ro, rd, 110.0, 20);
  var sceneT = hb.t;
  var c: vec3f;
  let tc = nc_sphereT(ro, rd, ball, 1.3);
  if (tc > 0.0 && tc < sceneT) {
    c = nc_ballBody(flash);
    sceneT = tc;
  } else if (hb.kind == 1) {
    let p = ro + rd * hb.t;
    c = mix(nc_facade(p, hb.n, hb.cell), nc_sky(rd), 1.0 - exp(-hb.t * 0.02));
  } else if (hb.kind == 0) {
    c = vec3f(0.02, 0.022, 0.03);
  } else {
    c = nc_sky(rd);
  }
  return array<vec3f, 2>(c, nc_ballGlow(ro, rd, ball, sceneT, flash));
}

fn visual_nc_city(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = vec2f(uv.x, -uv.y);
  let t = time;
  let district = nc_mode() > 0.5;

  var camZ = uni(0);
  if (camZ < 0.001) { camZ = t * 5.0; }

  var ro: vec3f;
  var look: vec3f;
  if (district) {                          // street level, dollying down the path
    ro = vec3f(4.5, 5.6, uni(26));         // the hook publishes the dolly (uni 26)
    look = normalize(vec3f(0.0, -0.10, 1.0));   // hand math mirrors this exactly
  } else {                                 // the drive: low, forward, swaying
    ro = vec3f(4.5 + sin(t * 0.08) * 1.2, 5.2 + sin(t * 0.20) * 0.30, camZ);
    look = normalize(vec3f(sin(t * 0.05) * 0.12, -0.12, 1.0));
  }
  let rt = normalize(cross(vec3f(0.0, 1.0, 0.0), look));
  let up = cross(look, rt);
  var rd = normalize(rt * p.x + up * (p.y * 0.72) + look * 1.5);
  rd = normalize(rd + vec3f(1.0e-4));

  var ball = nc_ball();
  if (ball.y < 0.01) { ball = vec3f(4.5, 2.0, camZ + 20.0); }
  let flash = uni(4);
  let horizon = nc_sky(vec3f(rd.x, max(rd.y, 0.02), rd.z));
  var col = nc_sky(rd);

  let hit = nc_traceCity(ro, rd, 220.0, 44);
  var hitT = hit.t;
  var kind = hit.kind;

  let tc = nc_sphereT(ro, rd, ball, 1.3);
  if (tc > 0.0 && tc < hitT) { hitT = tc; kind = 2; }

  // enemies — red hunters coming up the street (uni 16..24; 0 = empty slot)
  var eHit = -1;
  if (district) {
    for (var ei = 0; ei < 3; ei++) {
      let e = vec3f(uni(16 + ei * 3), uni(17 + ei * 3), uni(18 + ei * 3));
      if (e.y < 0.01) { continue; }
      let te = nc_sphereT(ro, rd, e, 1.5);
      if (te > 0.0 && te < hitT) { hitT = te; kind = 4; eHit = ei; }
    }
  }

  if (kind == 4) {
    let e = vec3f(uni(16 + eHit * 3), uni(17 + eHit * 3), uni(18 + eHit * 3));
    let hp = ro + rd * hitT;
    let nn = normalize(hp - e);
    let rim = pow(1.0 - max(dot(nn, -rd), 0.0), 2.0);
    let beat = 0.75 + 0.25 * sin(t * 6.0 + f32(eHit) * 2.1);
    col = vec3f(2.4, 0.16, 0.12) * beat + vec3f(3.0, 0.5, 0.25) * rim;
  } else if (kind == 2) {
    let hp = ro + rd * hitT;
    let nn = normalize(hp - ball);
    let rim = pow(1.0 - max(dot(nn, -rd), 0.0), 2.0);
    col = nc_ballBody(flash) + vec3f(1.2, 0.6, 0.25) * rim;
  } else if (kind == 1) {
    let hp = ro + rd * hitT;
    var mcol = nc_facade(hp, hit.n, hit.cell);
    mcol += nc_sky(hit.n) * 0.04;
    col = mix(mcol, horizon, 1.0 - exp(-hitT * 0.014));
  } else if (kind == 0) {
    let hp = ro + rd * hitT;
    let rip = vnoise(hp.xz * 0.8 + vec2f(0.0, t * 0.3)) - 0.5;
    let rn = normalize(vec3f(rip * 0.08, 1.0, rip * 0.08));
    let rrd = normalize(reflect(rd, rn) + vec3f(1.0e-4));
    let refl = nc_reflColor(hp + rn * 0.05, rrd, ball, flash);
    let fres = pow(1.0 - max(-rd.y, 0.0), 4.0);
    var road = mix(vec3f(0.015, 0.017, 0.024), refl[0], clamp(fres * 0.7 + 0.15, 0.0, 1.0));
    road += refl[1] * 0.65;
    col = mix(road, horizon, 1.0 - exp(-hitT * 0.014));
  }

  col += nc_ballGlow(ro, rd, ball, hitT, flash);

  if (district) {
    // enemy glow + the red sting when one gets through
    for (var gi = 0; gi < 3; gi++) {
      let e = vec3f(uni(16 + gi * 3), uni(17 + gi * 3), uni(18 + gi * 3));
      if (e.y < 0.01) { continue; }
      let oc2 = e - ro;
      let tca = dot(oc2, rd);
      if (tca > 0.0 && tca < hitT + 3.0) {
        let dsq = max(dot(oc2, oc2) - tca * tca, 0.0);
        col += vec3f(2.2, 0.2, 0.14) * exp(-dsq * 0.6) * 0.35;
      }
    }
    col += vec3f(1.4, 0.06, 0.04) * uni(25) * pow(length(p), 2.0) * 0.8;
  }

  return vec4f(col, 1.0);
}

fn ga_rd(q: vec3f, h: f32) -> f32 {
  // rhombic dodecahedron: max |dot(q, n)| over the six <110> normals, minus half-width
  let r2 = 0.70710678;
  var m = abs(dot(q, vec3f(r2, r2, 0.0)));
  m = max(m, abs(dot(q, vec3f(r2, -r2, 0.0))));
  m = max(m, abs(dot(q, vec3f(r2, 0.0, r2))));
  m = max(m, abs(dot(q, vec3f(r2, 0.0, -r2))));
  m = max(m, abs(dot(q, vec3f(0.0, r2, r2))));
  m = max(m, abs(dot(q, vec3f(0.0, r2, -r2))));
  return m - h;
}

fn ga_edge(q: vec3f) -> f32 {
  // crystal bevel: how close the two largest face distances are
  let r2 = 0.70710678;
  var a = abs(dot(q, vec3f(r2, r2, 0.0)));
  var b = abs(dot(q, vec3f(r2, -r2, 0.0)));
  if (b > a) { let t = a; a = b; b = t; }
  let c3 = abs(dot(q, vec3f(r2, 0.0, r2)));
  if (c3 > a) { b = a; a = c3; } else if (c3 > b) { b = c3; }
  let c4 = abs(dot(q, vec3f(r2, 0.0, -r2)));
  if (c4 > a) { b = a; a = c4; } else if (c4 > b) { b = c4; }
  let c5 = abs(dot(q, vec3f(0.0, r2, r2)));
  if (c5 > a) { b = a; a = c5; } else if (c5 > b) { b = c5; }
  let c6 = abs(dot(q, vec3f(0.0, r2, -r2)));
  if (c6 > a) { b = a; a = c6; } else if (c6 > b) { b = c6; }
  return smoothstep(0.045, 0.008, a - b);
}

fn ga_cellpos(packed: f32) -> vec3f {
  let ty = floor(packed / 1000.0);
  let idx = packed - ty * 1000.0;
  let kz = floor(idx / 81.0);
  let rem = idx - kz * 81.0;
  let jy = floor(rem / 9.0);
  let ix = rem - jy * 9.0;
  return (vec3f(ix, jy, kz) - vec3f(4.0)) * 0.62;
}
fn ga_celltype(packed: f32) -> f32 { return floor(packed / 1000.0); }

fn ga_rot(p: vec3f, yaw: f32, pitch: f32) -> vec3f {
  let cy = cos(yaw); let sy = sin(yaw);
  var q = vec3f(cy * p.x + sy * p.z, p.y, -sy * p.x + cy * p.z);
  let cp = cos(pitch); let sp = sin(pitch);
  return vec3f(q.x, cp * q.y - sp * q.z, sp * q.y + cp * q.z);
}

// scene SDF over all cells: returns (distance, cellIndex)
fn ga_map(p: vec3f) -> vec2f {
  let n = i32(uni(0));
  let H = 0.438;   // 0.62 / sqrt(2): faces kiss exactly
  var best = 1e5;
  var mat = -1.0;
  for (var i = 0; i < 56; i++) {
    if (i >= n) { break; }
    let packed = uni(8 + i);
    let c = ga_cellpos(packed);
    // cheap sphere reject before the six planes
    let ds = length(p - c) - 0.78;
    if (ds > best) { continue; }
    let d = ga_rd(p - c, H);
    if (d < best) { best = d; mat = f32(i); }
  }
  return vec2f(best, mat);
}

fn ga_stars(rd: vec3f, streak: f32, t: f32) -> vec3f {
  // starfield; streaks along +x when flying
  var c = vec3f(0.004, 0.005, 0.012);
  let sp = rd.yz * 22.0 + vec2f(rd.x * 4.0, 0.0);
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let cell = floor(sp * (1.0 + fl * 0.7) + fl * 13.0);
    let h = hash21(cell);
    let fp = fract(sp * (1.0 + fl * 0.7)) - 0.5;
    var star = step(0.985, h) * smoothstep(0.28, 0.04, length(fp));
    // streaking: smear along x with speed
    let fps = vec2f(fp.x / (1.0 + streak * 6.0), fp.y);
    star = max(star, step(0.985, h) * smoothstep(0.28, 0.04, length(fps)) * streak);
    c += vec3f(0.7, 0.75, 0.9) * star * (0.4 + 0.4 * sin(t * (0.5 + h) + h * 30.0));
  }
  // faint nebula
  c += vec3f(0.05, 0.02, 0.08) * pow(max(0.0, 1.0 - abs(rd.y * 1.6 - 0.2)), 3.0) * (0.5 + 0.5 * vnoise(rd.xz * 3.0));
  return c;
}

fn visual_ga_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let scr = vec2f(uv.x, -uv.y);
  let mode = uni(1);
  let yaw = uni(2);
  let pitch = uni(3);
  let plume = uni(5);
  let tumble = uni(6);
  let speed01 = uni(7);

  // orbit camera
  let R = 7.6;
  let ro0 = vec3f(R * cos(pitch) * cos(yaw), R * sin(pitch), R * cos(pitch) * sin(yaw));
  let fwd = normalize(-ro0);
  let right = normalize(cross(vec3f(0.0, 1.0, 0.0), fwd));
  let up = cross(fwd, right);
  var rd = normalize(fwd * 1.9 + right * scr.x + up * scr.y);
  let ro = ro0;

  var col = ga_stars(rd, speed01 * clamp(mode, 0.0, 1.0), time);

  // in flight the whole ship tumbles — rotate the RAY instead of every cell
  var rro = ro;
  var rrd = rd;
  if (mode > 0.5) {
    rro = ga_rot(ro, 0.0, tumble);
    rrd = ga_rot(rd, 0.0, tumble);
    rro = ga_rot(rro, tumble * 0.35, 0.0);
    rrd = ga_rot(rrd, tumble * 0.35, 0.0);
  }

  // march
  var t = 0.0;
  var hit = false;
  var mm = vec2f(0.0, -1.0);
  // whole-ship bounding sphere: pixels that can't hit anything never march
  let toC = -rro;
  let bClose = dot(toC, rrd);
  let bD2 = dot(toC, toC) - bClose * bClose;
  if (bD2 < 16.0 && bClose > 0.0) {
    t = max(0.0, bClose - 4.0);
    for (var i = 0; i < 44; i++) {
      let p = rro + rrd * t;
      mm = ga_map(p);
      if (mm.x < 0.0025) { hit = true; break; }
      t = t + mm.x * 1.08;
      if (t > bClose + 4.5) { break; }
    }
  }

  if (hit) {
    let p = rro + rrd * t;
    let e = 0.004;
    let d0 = mm.x;
    let nr = normalize(vec3f(
      ga_map(p + vec3f(e, 0.0, 0.0)).x - d0,
      ga_map(p + vec3f(0.0, e, 0.0)).x - d0,
      ga_map(p + vec3f(0.0, 0.0, e)).x - d0));
    let packed = uni(8 + i32(mm.y));
    let ty = ga_celltype(packed);
    let c = ga_cellpos(packed);
    let q = p - c;
    let edge = ga_edge(q);

    // materials by purpose — every component has a FEATURE, not just a color
    var alb = vec3f(0.5);
    var emis = vec3f(0.0);
    var gloss = 24.0;
    var ety = ty;
    var isGhost = false;
    if (ty > 5.5) { ety = ty - 6.0; isGhost = true; }   // ghost previews the real part

    let qn = normalize(q + vec3f(1e-5));
    if (ety < 0.5) {          // CORE — molten heart, pulsing veins
      alb = vec3f(0.55, 0.42, 0.20);
      let vein = smoothstep(0.55, 0.9, vnoise(q.xy * 9.0 + vec2f(time * 0.4, q.z * 9.0)));
      emis = vec3f(2.2, 1.3, 0.35) * (0.45 + 0.4 * sin(time * 2.2)) * (1.0 - edge) * (0.5 + vein);
      gloss = 60.0;
    } else if (ety < 1.5) {   // THRUSTER — gunmetal with a hot engine bell on the rear pole (-x)
      alb = vec3f(0.22, 0.24, 0.28);
      let bell = pow(max(0.0, dot(qn, vec3f(-1.0, 0.0, 0.0))), 6.0);
      alb = mix(alb, vec3f(0.10, 0.08, 0.07), bell * 0.7);
      let idle = 0.35 + 0.25 * sin(time * 3.0);
      emis = vec3f(2.0, 0.9, 0.25) * bell * max(idle, plume * 1.6);   // always glows: THIS is an engine
      gloss = 90.0;
    } else if (ety < 2.5) {   // TANK — steel drum with weld rings
      alb = vec3f(0.46, 0.52, 0.58) * (0.9 + 0.1 * vnoise(q.xy * 30.0));
      let ring = smoothstep(0.10, 0.04, abs(fract(q.x * 3.2 + 0.5) - 0.5));
      alb = mix(alb, vec3f(0.16, 0.18, 0.22), ring * 0.8);
      gloss = 120.0;
    } else if (ety < 3.5) {   // SOLAR — blue glass with a visible cell grid
      let irid = 0.5 + 0.5 * sin(dot(nr, vec3f(4.0, 7.0, 5.0)) + time * 0.3);
      alb = mix(vec3f(0.07, 0.12, 0.38), vec3f(0.15, 0.05, 0.38), irid);
      let gy = smoothstep(0.09, 0.03, abs(fract(q.y * 5.0) - 0.5));
      let gz = smoothstep(0.09, 0.03, abs(fract(q.z * 5.0) - 0.5));
      alb = mix(alb, vec3f(0.02, 0.03, 0.08), max(gy, gz) * 0.85);
      emis = vec3f(0.10, 0.16, 0.45) * irid * 0.5 * (1.0 - max(gy, gz));
      gloss = 200.0;
    } else if (ety < 4.5) {   // CARGO — strapped amber crate
      alb = vec3f(0.55, 0.38, 0.16) * (0.85 + 0.15 * vnoise(q.xz * 22.0));
      let strap = max(smoothstep(0.10, 0.04, abs(q.y)), smoothstep(0.10, 0.04, abs(q.z)));
      alb = mix(alb, vec3f(0.20, 0.13, 0.06), strap * 0.85);
      gloss = 30.0;
    } else {                  // SHIELD — humming crystal bubble
      alb = vec3f(0.50, 0.70, 0.78);
      let hum = 0.5 + 0.5 * sin(time * 1.6 + dot(qn, vec3f(3.0, 5.0, 4.0)));
      emis = vec3f(0.12, 0.35, 0.42) * (0.4 + 0.5 * hum);
      gloss = 160.0;
    }
    if (isGhost) {            // ghost: the part's own look, cyan-pulsed and hollow
      let pulse = 0.45 + 0.4 * sin(time * 5.0);
      emis = alb * pulse * 1.2 + emis * 0.6 + vec3f(0.2, 0.9, 1.1) * edge * 1.8 * pulse;
      alb = alb * 0.22;
    }

    // two-light studio + rim
    let L1 = normalize(vec3f(0.6, 0.75, -0.35));
    let L2 = normalize(vec3f(-0.55, -0.2, 0.6));
    let dif = clamp(dot(nr, L1), 0.0, 1.0) * 1.15 + clamp(dot(nr, L2), 0.0, 1.0) * 0.28;
    let hlf = normalize(L1 - rrd);
    let spec = pow(clamp(dot(nr, hlf), 0.0, 1.0), gloss) * 0.9;
    let fres = pow(clamp(1.0 + dot(rrd, nr), 0.0, 1.0), 3.0);
    var cc = alb * (vec3f(0.10, 0.11, 0.16) + vec3f(1.0, 0.95, 0.88) * dif);
    cc += vec3f(spec);
    cc += vec3f(0.35, 0.45, 0.7) * fres * 0.35;
    // crystal edges: darker bevel + a thread of light
    cc = mix(cc, cc * 0.35 + vec3f(0.5, 0.55, 0.65) * 0.35, edge * 0.85);
    cc += emis;
    col = cc;
  }

  // thruster plumes — additive glow, distance from the ray to points trailing each bell
  if (plume > 0.02) {
    let n = i32(uni(0));
    for (var i = 0; i < 56; i++) {
      if (i >= n) { break; }
      let packed = uni(8 + i);
      if (ga_celltype(packed) != 1.0) { continue; }
      let c = ga_cellpos(packed);
      for (var s = 1; s <= 3; s++) {
        let fs = f32(s);
        var pp = c - vec3f(fs * 0.5, 0.0, 0.0);   // exhaust streams -x (flight axis)
        if (mode > 0.5) {
          pp = ga_rot(pp, -tumble * 0.35, 0.0);
          pp = ga_rot(pp, 0.0, -tumble);
        }
        let w = pp - ro;
        let dRay = length(cross(rd, w));
        let flick = 0.8 + 0.25 * sin(time * 17.0 + fs * 2.0 + f32(i));
        col += vec3f(1.6, 0.75, 0.22) * exp(-dRay * dRay * (30.0 + fs * 22.0)) * plume * flick / fs;
      }
    }
  }

  return vec4f(col, 1.0);
}

fn visual_ga_hud(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [selectedPart 1..5, fuel01, balance01 (1 = clean), mode]
  var c = vec3f(0.0);
  var a = 0.0;
  // component legend: thruster / tank / solar / cargo / shield — W/S moves the ring
  for (var i = 1; i <= 5; i++) {
    let fi = f32(i);
    var tint = vec3f(1.5, 0.55, 0.15);                       // thruster ember
    if (i == 2) { tint = vec3f(0.55, 0.62, 0.70); }          // tank steel
    if (i == 3) { tint = vec3f(0.25, 0.35, 1.2); }           // solar blue
    if (i == 4) { tint = vec3f(0.9, 0.55, 0.18); }           // cargo amber
    if (i == 5) { tint = vec3f(0.35, 0.95, 1.1); }           // shield cyan
    let ctr = vec2f(-0.72 + (fi - 1.0) * 0.36, 0.30);
    let q = (uv - ctr) * vec2f(7.0, 3.2);
    let d = length(q);
    let sel = select(0.0, 1.0, abs(p.x - fi) < 0.5);
    c += tint * exp(-d * d * (2.2 - sel * 0.8)) * (0.35 + 0.75 * sel);
    // selection ring
    c += vec3f(0.9, 1.0, 1.1) * exp(-pow((d - 0.75) * 6.0, 2.0)) * sel * (0.7 + 0.3 * sin(time * 6.0));
    a = max(a, exp(-d * d * 1.4) * (0.5 + 0.4 * sel));
  }
  // fuel + balance bars underneath
  for (var i = 0; i < 2; i++) {
    let y0 = -0.30 - f32(i) * 0.42;
    var v = p.y;
    var tint = vec3f(0.4, 0.9, 1.2);
    if (i == 1) { v = p.z; tint = mix(vec3f(1.3, 0.3, 0.2), vec3f(0.3, 1.2, 0.5), p.z); }
    let bx = (uv.x + 0.9) / 1.8;
    if (bx > 0.0 && bx < 1.0 && abs(uv.y - y0) < 0.10) {
      let on = step(bx, clamp(v, 0.0, 1.0));
      c += mix(vec3f(0.05, 0.05, 0.07), tint, on) * exp(-pow((uv.y - y0) * 14.0, 2.0));
      a = max(a, exp(-pow((uv.y - y0) * 12.0, 2.0)) * 0.75);
    }
  }
  return vec4f(c, clamp(a, 0.0, 1.0) * 0.9);
}

// state encoding: r = (1-u)*A*0.35, g = v*B, b = art (display only, never decoded)
// A,B are palette amplitudes (>= 0.35 so state stays decodable)
fn sg_dec(c: vec4f, A: f32, B: f32) -> vec2f {
  return vec2f(clamp(c.x, 0.0, 1.0) / (0.35 * max(A, 0.35)), clamp(c.y, 0.0, 1.0) / max(B, 0.35));
}
// one thermostat's published feed bias, read from the frame
fn sg_bias(n: vec2f, p: vec2f) -> f32 {
  let c = prevAt(n * 64.0 + vec2f(32.0, 32.0) - p);
  return (clamp(c.y, 0.0, 1.0) / 0.12 - 0.5) / 20.0;
}
fn sg_isCtrl(p: vec2i) -> bool {
  let m = p % vec2i(64, 64);
  return m.x == 32 && m.y == 32;
}
// neighbor state; controller pixels are not chemistry — substitute self
fn sg_nb(o: vec2f, cSelf: vec2f, A: f32, B: f32) -> vec2f {
  let np = vec2i(pix() + o);
  if (sg_isCtrl(np)) { return cSelf; }
  return sg_dec(prevAt(o), A, B);
}

fn visual_sg_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let A = clamp(uni(5), 0.35, 1.0);
  let B = clamp(uni(6), 0.35, 1.0);
  let Cc = clamp(uni(7), 0.0, 1.2);
  let booted = uni(9) > 0.5;
  let p = pix();

  // ── CONTROLLER pixels: measure, integrate, publish. 1px each, one per 64px cell ──
  if (sg_isCtrl(vec2i(p))) {
    if (!booted) { return vec4f(0.10 * 0.25, 0.5 * 0.12, 0.0, 1.0); }
    var OFS = array<vec2f, 8>(
      vec2f(0.0, 16.0), vec2f(0.0, -16.0), vec2f(16.0, 0.0), vec2f(-16.0, 0.0),
      vec2f(20.0, 20.0), vec2f(-20.0, 20.0), vec2f(20.0, -20.0), vec2f(-20.0, -20.0));
    var act = 0.0;
    for (var j = 0; j < 8; j++) { act += sg_dec(prevAt(OFS[j]), A, B).y; }
    act /= 8.0;
    let s = prevHere();
    let prevAct = clamp(s.x, 0.0, 1.0) / 0.25;
    let prevBias = (clamp(s.y, 0.0, 1.0) / 0.12 - 0.5) / 20.0;
    let prevLock = clamp(s.z, 0.0, 1.0) / 0.2;
    let sm = mix(prevAct, act, 0.04);
    let TARGET = 0.10;
    let bias = clamp(prevBias + (TARGET - sm) * 0.00045, -0.024, 0.024);
    let err = abs(TARGET - sm) / TARGET;
    let lock = mix(prevLock, clamp(1.0 - err, 0.0, 1.0), 0.006);
    return vec4f(sm * 0.25, (0.5 + bias * 20.0) * 0.12, lock * 0.2, 1.0);
  }

  let ax = max(abs(uv.x), abs(uv.y));

  // ── BEZEL: the set itself. Inner dead frame is the reaction's boundary ──
  if (ax > 0.94) {
    if (ax < 0.955) { return vec4f(0.0, 0.0, 0.0, 1.0); }
    var c = vec3f(0.055, 0.038, 0.028) * (0.85 + 0.3 * hash21(floor(p / 3.0)));
    // LED rail: one thermostat's verdict per column — amber hunts, green holds
    if (uv.y < -0.955) {
      let cl = floor((p - vec2f(0.0, 130.0)) / 64.0) * 64.0 + vec2f(32.0, 32.0);
      let cc = prevAt(cl - p);
      let lock = clamp(cc.z, 0.0, 1.0) / 0.2;
      let act = clamp(cc.x, 0.0, 1.0) / 0.25;
      let lx = p.x - cl.x;
      let led = exp(-lx * lx / 40.0);
      let hunting = 0.6 + 0.4 * sin(time * 6.0 + cl.x * 0.13);
      let lcol = mix(vec3f(1.0, 0.55, 0.15) * hunting, vec3f(0.25, 1.0, 0.4), clamp(lock * 1.15, 0.0, 1.0));
      c += lcol * led * (0.5 + 0.5 * clamp(act * 3.0, 0.0, 1.0)) * 2.2;
    }
    c += vec3f(0.4, 0.9, 0.5) * uni(8) * 0.12;   // retune flash
    if (c.x != c.x || c.y != c.y || c.z != c.z) { c = vec3f(0.02); }
    return vec4f(clamp(c, vec3f(0.0), vec3f(8.0)), 1.0);
  }

  // ── SUBSTRATE: Gray-Scott on the previous frame ──
  if (!booted) {
    // first light: sparse seeds in an empty universe
    let h = hash21(floor(p / 9.0));
    let v0 = select(0.0, 0.85, h > 0.978);
    return vec4f(0.0, v0 * B, 0.0, 1.0);
  }
  let cs = sg_dec(prevHere(), A, B);
  var la = 0.0;
  var lv = 0.0;
  var NO = array<vec2f, 4>(vec2f(2.0, 0.0), vec2f(-2.0, 0.0), vec2f(0.0, 2.0), vec2f(0.0, -2.0));
  var ND = array<vec2f, 4>(vec2f(2.0, 2.0), vec2f(2.0, -2.0), vec2f(-2.0, 2.0), vec2f(-2.0, -2.0));
  for (var j = 0; j < 4; j++) {
    let n1 = sg_nb(NO[j], cs, A, B);
    la += 0.2 * (n1.x - cs.x); lv += 0.2 * (n1.y - cs.y);
    let n2 = sg_nb(ND[j], cs, A, B);
    la += 0.05 * (n2.x - cs.x); lv += 0.05 * (n2.y - cs.y);
  }
  // the control layer, read through the frame — blended between the four
  // nearest thermostats so control varies smoothly across the picture
  let pc = (p - vec2f(32.0, 32.0)) / 64.0;
  let b0 = floor(pc);
  let bf = pc - b0;
  let bias = mix(
    mix(sg_bias(b0, p), sg_bias(b0 + vec2f(1.0, 0.0), p), bf.x),
    mix(sg_bias(b0 + vec2f(0.0, 1.0), p), sg_bias(b0 + vec2f(1.0, 1.0), p), bf.x), bf.y);

  let F = clamp(uni(3) + bias, 0.004, 0.095);
  let k = clamp(uni(4), 0.03, 0.08);
  let u = 1.0 - cs.x;
  let v = cs.y;
  let uvv = u * v * v;
  var un = clamp(u + (1.0 * (-la) - uvv + F * (1.0 - u)), 0.0, 1.0);
  var vn = clamp(v + (0.5 * lv + uvv - (F + k) * v), 0.0, 1.0);

  // touch pours reagent — you can seed reality by hand
  if (uni(2) > 0.5) {
    let dm = uv - vec2f(uni(0), uni(1));
    vn = max(vn, 0.9 * exp(-dot(dm, dm) * 2200.0));
  }

  // art channel: glow from concentration + the retune ripple
  let pl = uni(8);
  var art = pow(vn, 1.5) * 3.0 * Cc;
  if (pl > 0.001) {
    let dc = abs(length(uv) - (1.0 - pl) * 1.6);
    art += pl * 1.2 * exp(-dc * dc * 160.0);
  }
  var outc = vec3f((1.0 - un) * A * 0.35, vn * B, art);
  if (outc.x != outc.x || outc.y != outc.y || outc.z != outc.z) { outc = vec3f(0.0); }
  return vec4f(clamp(outc, vec3f(0.0), vec3f(4.0)), 1.0);
}

fn hx_seg(p: vec2f, a: vec2f, b: vec2f) -> f32 {
  let pa = p - a;
  let ba = b - a;
  let h = clamp(dot(pa, ba) / max(dot(ba, ba), 1e-6), 0.0, 1.0);
  return length(pa - ba * h);
}

fn hx_moon(rel: vec2f, r: f32, ph: f32) -> f32 {
  let d = length(rel);
  let disc = smoothstep(r, r * 0.9, d);
  let bc = vec2f(cos(6.2831853 * ph), sin(6.2831853 * ph)) * r * 0.72;
  let bite = smoothstep(r * 0.98, r * 0.84, length(rel - bc));
  return disc * (1.0 - bite * 0.93);
}

fn hx_star_pos(i: i32) -> vec2f {
  if (i == 0) { return vec2f(0.00, 0.46); }
  if (i == 1) { return vec2f(-0.11, 0.28); }
  if (i == 2) { return vec2f(0.00, 0.11); }
  if (i == 3) { return vec2f(0.04, -0.10); }
  if (i == 4) { return vec2f(0.00, -0.25); }
  if (i == 5) { return vec2f(0.27, -0.30); }
  return vec2f(0.40, -0.52);
}
fn hx_edge(e: i32) -> vec2f {   // (from, to) star indices per required edge
  if (e == 0) { return vec2f(0.0, 1.0); }
  if (e == 1) { return vec2f(1.0, 2.0); }
  if (e == 2) { return vec2f(2.0, 3.0); }
  if (e == 3) { return vec2f(3.0, 4.0); }
  if (e == 4) { return vec2f(3.0, 5.0); }
  return vec2f(5.0, 6.0);
}

fn visual_helios_chapters(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let act = uni(24);
  if (act < 1.5) { return vec4f(0.0); }
  let t = time;
  let mc = vec2f(uni(0), uni(1));

  // ════ CHAPTER II — THE DROWNED MOON ════
  if (act < 2.5) {
    let ph = uni(2);
    let nvy = clamp(uv.y, -1.3, 1.3);
    var col = mix(vec3f(0.010, 0.018, 0.038), vec3f(0.030, 0.055, 0.095), 0.5 - 0.5 * nvy);
    let ca = sin(uv.x * 9.0 + sin(nvy * 5.0 + t * 0.4) * 1.5 + t * 0.5);
    col += vec3f(0.028, 0.05, 0.07) * (0.5 + 0.5 * ca) * 0.5;
    let sp = uv * 14.0 + vec2f(sin(t * 0.2 + nvy * 2.0) * 0.05, 0.0);
    let sh = hash21(floor(sp));
    if (sh > 0.972) {
      col += vec3f(0.35, 0.45, 0.65) * smoothstep(0.2, 0.03, length(fract(sp) - 0.5)) * (0.4 + 0.4 * sin(t * 1.5 + sh * 40.0));
    }
    let bp = vec2f(uv.x * 10.0, nvy * 6.0 - t * 0.35);
    let bh = hash21(floor(bp));
    if (bh > 0.955) {
      col += vec3f(0.08, 0.13, 0.17) * smoothstep(0.16, 0.02, length(fract(bp) - 0.5));
    }
    let R = 0.68;
    for (var i = 0; i < 6; i++) {
      let fi = f32(i);
      let a = 6.2831853 * fi / 6.0 - 1.5707963;
      let c = vec2f(cos(a), sin(a)) * R;
      let rel = uv - c;
      if (abs(rel.x) < 0.22 && abs(rel.y) < 0.22) {
        let lit = clamp(uni(4 + i), 0.0, 1.0);
        let stone = hx_moon(rel, 0.075, fi / 6.0);
        let scol = mix(vec3f(0.15, 0.17, 0.23), vec3f(1.35, 1.30, 1.05), lit);
        col = mix(col, scol, stone * (0.4 + 0.6 * lit));
        col += vec3f(0.05, 0.06, 0.09) * exp(-dot(rel, rel) * 90.0) * (1.0 - lit);
        let dp = abs(fract(ph - fi / 6.0 + 0.5) - 0.5);
        let phMatch = smoothstep(0.085, 0.03, dp) * (1.0 - lit);
        col += vec3f(1.0, 0.72, 0.28) * exp(-pow((length(rel) - 0.085) * 26.0, 2.0)) * phMatch * (0.6 + 0.4 * sin(t * 5.0));
        col += vec3f(0.85, 0.85, 0.6) * exp(-dot(rel, rel) * 150.0) * lit * 0.9;
      }
    }
    // the moon-tree: the door down to CHAPTER III
    let wt = clamp(uni(11), 0.0, 1.0);
    if (wt > 0.005) {
      let g1 = clamp(wt * 3.0, 0.0, 1.0);
      let g2 = clamp(wt * 3.0 - 1.0, 0.0, 1.0);
      let g3 = clamp(wt * 3.0 - 2.0, 0.0, 1.0);
      let p0 = vec2f(0.0, 0.42);
      let p1 = p0 + vec2f(-0.03, -0.20) * g1;
      let p2 = p1 + vec2f(0.05, -0.19) * g2;
      let p3 = p2 + vec2f(-0.02, -0.16) * g3;
      var td = hx_seg(uv, p0, p1) - 0.022 * (0.6 + 0.4 * g1);
      td = min(td, hx_seg(uv, p1, p2) - 0.016);
      td = min(td, hx_seg(uv, p2, p3) - 0.011);
      for (var bi = 0; bi < 5; bi++) {
        let fb = f32(bi);
        let gb = clamp(wt * 4.0 - 2.2 - fb * 0.25, 0.0, 1.0);
        if (gb > 0.01) {
          let root = mix(p2, p3, 0.2 + fb * 0.2);
          let ang = -1.5707963 + (fb - 2.0) * 0.55 + sin(t * 0.4 + fb) * 0.04;
          let tip = root + vec2f(cos(ang), sin(ang)) * (0.14 + fb * 0.014) * gb;
          td = min(td, hx_seg(uv, root, tip) - 0.006);
          col += vec3f(1.15, 1.10, 0.75) * exp(-dot(uv - tip, uv - tip) * 900.0) * gb * (0.8 + 0.3 * sin(t * 2.0 + fb * 2.1));
          col += vec3f(0.55, 0.60, 0.45) * exp(-dot(uv - tip, uv - tip) * 120.0) * gb * 0.35;
        }
      }
      if (td < 0.0) { col = mix(vec3f(0.72, 0.68, 0.58), vec3f(0.35, 0.30, 0.24), clamp((uv.y - p2.y) * 2.0, 0.0, 1.0)); }
      col += vec3f(1.0, 0.85, 0.45) * exp(-dot(uv - p3, uv - p3) * 9.0) * wt * 0.30;
      col += vec3f(0.9, 0.75, 0.35) * wt * (0.035 + 0.03 * sin(t * 2.1));
    }
    // the drowned moon you carry
    let mr = uv - mc;
    let held = hx_moon(mr, 0.055, ph);
    col = mix(col, vec3f(1.55, 1.55, 1.35), held);
    col += vec3f(0.45, 0.5, 0.68) * exp(-dot(mr, mr) * 55.0) * (0.45 + 0.4 * uni(3));
    col *= 1.0 - 0.4 * pow(length(vec2f(uv.x, nvy)) * 0.72, 3.0);
    if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
    return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
  }

  // ════ CHAPTER III — THE BEARER: write yourself into the sky ════
  let won = uni(10);
  let bloom = clamp(uni(11), 0.0, 1.0);
  var col = mix(vec3f(0.004, 0.006, 0.018), vec3f(0.014, 0.018, 0.045), 0.5 - 0.5 * uv.y);
  // the ordinary stars, humble
  let sp = uv * 15.0;
  let sh = hash21(floor(sp));
  if (sh > 0.976) {
    col += vec3f(0.5, 0.55, 0.75) * smoothstep(0.2, 0.03, length(fract(sp) - 0.5)) * (0.3 + 0.35 * sin(t * 1.1 + sh * 47.0));
  }

  // the lit threads of the figure
  for (var e = 0; e < 6; e++) {
    let el = clamp(uni(4 + e), 0.0, 1.0);
    if (el > 0.01) {
      let pr = hx_edge(e);
      let a = hx_star_pos(i32(pr.x));
      let b = hx_star_pos(i32(pr.y));
      let dd = hx_seg(uv, a, b);
      // a pulse walks each finished thread
      let along = clamp(dot(uv - a, b - a) / max(dot(b - a, b - a), 1e-5), 0.0, 1.0);
      let pulse = exp(-pow((along - fract(t * 0.23 + f32(e) * 0.17)) * 6.0, 2.0));
      col += vec3f(1.0, 0.92, 0.62) * exp(-dd * 90.0) * el * (0.5 + 0.35 * pulse + bloom * 0.5);
    }
  }

  // the drag in progress: a thread from the held star to your hand
  if (uni(12) > 0.5) {
    let a = vec2f(uni(2), uni(3));
    let dd = hx_seg(uv, a, mc);
    col += vec3f(0.8, 0.85, 1.0) * exp(-dd * 110.0) * (0.35 + 0.15 * sin(t * 6.0));
  }

  // the seven story-stars, brighter than the sky's own
  for (var i = 0; i < 7; i++) {
    let c = hx_star_pos(i);
    let d = length(uv - c);
    let tw = 0.7 + 0.3 * sin(t * 1.7 + f32(i) * 2.3);
    var sc = vec3f(0.95, 0.95, 1.05);
    if (i == 6) { sc = vec3f(1.2, 1.0, 0.55); }   // the light he carries
    col += sc * exp(-d * d * 2200.0) * (1.1 + bloom) * tw;
    col += sc * exp(-d * 26.0) * 0.10 * (1.0 + bloom * 1.6);
  }

  // complete: the Bearer blazes, and a door of the same light opens below
  if (bloom > 0.003) {
    col += vec3f(0.35, 0.30, 0.18) * bloom * (0.10 + 0.05 * sin(t * 0.8));
    let dp = uv - vec2f(0.0, 0.64);
    let door = smoothstep(0.15, 0.12, abs(dp.x)) * smoothstep(0.12, 0.09, abs(dp.y));
    col += vec3f(1.0, 0.9, 0.6) * door * bloom * (0.4 + 0.1 * sin(t * 2.0));
  }

  // your hand — a faint reaching light
  col += vec3f(0.9, 0.9, 1.0) * exp(-dot(uv - mc, uv - mc) * 800.0) * 0.5;

  col *= 1.0 - 0.4 * pow(length(uv) * 0.72, 3.0);
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
}

fn visual_proof_pool(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = (uv + vec2f(1.0)) * 256.0;
  let t = time;

  // still dark water, faint caustics
  var col = vec3f(0.012, 0.020, 0.026);
  let ca = vnoise(p * 0.03 + vec2f(t * 0.05, t * 0.03)) * vnoise(p * 0.05 - vec2f(t * 0.04, 0.0));
  col += vec3f(0.010, 0.030, 0.036) * smoothstep(0.18, 0.45, ca);

  // ── LAW: the well (uni0 on, 1,2 pos) ──
  if (uni(0) > 0.5) {
    let wp = p - vec2f(uni(1), uni(2));
    let d = length(wp);
    col += vec3f(1.4, 1.0, 0.35) * exp(-d * 0.035) * (0.55 + 0.25 * sin(t * 2.2));
    let ring = abs(fract(d * 0.02 - t * 0.22) - 0.5);
    col += vec3f(0.5, 0.38, 0.12) * smoothstep(0.10, 0.0, ring) * exp(-d * 0.012);
  }

  // ── LAW: the wind (uni4 on, 5,6 dir) ──
  if (uni(4) > 0.5) {
    let wdir = normalize(vec2f(uni(5), uni(6)) + vec2f(1.0e-4));
    let along = dot(p, wdir);
    let across = dot(p, vec2f(-wdir.y, wdir.x));
    let streak = smoothstep(0.75, 1.0, vnoise(vec2f(along * 0.05 - t * 3.0, across * 0.35)));
    col += vec3f(0.10, 0.16, 0.18) * streak;
  }

  // ── LAW: the vortex (uni10 on, 11,12 pos) ──
  if (uni(10) > 0.5) {
    let vp = p - vec2f(uni(11), uni(12));
    let d = length(vp);
    let ang = atan2(vp.y, vp.x);
    let arm = abs(fract((ang * 0.955 + d * 0.02 - t * 0.5)) - 0.5);
    col += vec3f(0.15, 0.35, 0.45) * smoothstep(0.12, 0.0, arm) * exp(-d * 0.015);
  }

  // ── LAW: the predator (uni7 on, 8,9 pos) ──
  if (uni(7) > 0.5) {
    let pp = p - vec2f(uni(8), uni(9));
    let d = length(pp);
    col += vec3f(1.6, 0.12, 0.10) * exp(-d * 0.09) * (0.7 + 0.3 * sin(t * 9.0));
    if (d < 5.0) { col = vec3f(2.0, 0.3, 0.2); }
  }

  col *= 1.0 - 0.5 * pow(length(uv), 3.0);   // pool edge falls to dark
  return vec4f(col, 1.0);
}

fn visual_mote(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let d = length(uv);
  let glow = exp(-d * 2.6);
  if (glow < 0.03) { return vec4f(0.0); }
  return vec4f(color.rgb * glow * 1.8, glow);
}
